using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.UI;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        // Mission state
        private bool missionActive = false;
        private Vehicle missionVehicle = null;
        private DateTime missionStartTime;
        private TimeSpan missionDuration = TimeSpan.FromMinutes(10);
        private bool missionFailed = false;
        private bool missionSucceeded = false;

        // Cooldowns for chat effects
        private Dictionary<string, DateTime> cooldowns = new Dictionary<string, DateTime>();

        // Active effects with timers
        private bool tiresInvulnerable = false;
        private DateTime tireInvulnEnd;
        private bool engineBoosted = false;
        private DateTime engineBoostEnd;
        private bool tractionReduced = false;
        private DateTime tractionReducedEnd;
        private bool engineStalled = false;
        private DateTime engineStallEnd;

        // LIVE Studio client
        private LiveStudioClient _client;

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();

            // Mission lifecycle when active
            if (missionActive && !missionFailed && !missionSucceeded)
            {
                // Handle elapsed time, accounting for game pause
                if (!Game.IsPaused)
                {
                    TimeSpan elapsed = DateTime.Now - missionStartTime;
                    if (elapsed >= missionDuration)
                    {
                        // Time ran out – check if still valid
                        if (missionVehicle != null && missionVehicle.Exists() &&
                            Game.Player.Character.IsInVehicle(missionVehicle))
                        {
                            SucceedMission();
                        }
                        else
                        {
                            FailMission("You left the vehicle or it was destroyed before time was up.");
                        }
                        return;
                    }
                    DisplayTimer(missionDuration - elapsed);
                }

                // Verify player is still in the mission vehicle
                Ped player = Game.Player.Character;
                if (!player.IsInVehicle(missionVehicle) || missionVehicle == null || !missionVehicle.Exists() ||
                    ((Entity)missionVehicle).HealthFloat <= 0)
                {
                    FailMission("You left the vehicle or it was destroyed.");
                    return;
                }

                // Manage temporary effects
                if (tiresInvulnerable && DateTime.Now >= tireInvulnEnd)
                {
                    tiresInvulnerable = false;
                    if (missionVehicle != null && missionVehicle.Exists())
                        missionVehicle.CanTiresBurst = true;
                }

                // Engine multiplier logic (priority: stall > boost > normal)
                float desiredPower = 1.0f;
                if (engineStalled) desiredPower = 0.0f;
                else if (engineBoosted) desiredPower = 2.0f;

                if (missionVehicle != null && missionVehicle.Exists())
                    missionVehicle.EnginePowerMultiplier = desiredPower;

                if (engineStalled && DateTime.Now >= engineStallEnd)
                {
                    engineStalled = false;
                }
                if (engineBoosted && DateTime.Now >= engineBoostEnd)
                {
                    engineBoosted = false;
                }
                if (tractionReduced && DateTime.Now >= tractionReducedEnd)
                {
                    tractionReduced = false;
                    if (missionVehicle != null && missionVehicle.Exists())
                        missionVehicle.EngineTorqueMultiplier = 1.0f;
                }
            }
            else if (!missionActive)
            {
                // Toggle start with F5 while player is in a vehicle
                if (Game.IsKeyPressed(Keys.F5))
                {
                    if (!cooldowns.ContainsKey("KB_F5") || DateTime.Now > cooldowns["KB_F5"])
                    {
                        cooldowns["KB_F5"] = DateTime.Now.AddSeconds(1);
                        Ped player = Game.Player.Character;
                        if (player.IsInVehicle())
                        {
                            StartMission(player.CurrentVehicle);
                        }
                        else
                        {
                            GTA.UI.Notification.Show("~y~You must be in a vehicle to start the mission.");
                        }
                    }
                }
            }
        }

        private void OnAborted(object sender, EventArgs e)
        {
            if (_client != null) _client.Dispose();
            CleanupMission();
        }

        // LIVE Studio event handler (off-thread)
        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat)
            {
                MainThreadDispatcher.Enqueue(() => ProcessChatCommand(chat.Content));
            }
            // No gift triggers
        }

        private void ProcessChatCommand(string message)
        {
            if (!missionActive) return;

            string cmd = message.ToLowerInvariant().Trim();
            if (cmd == "!repair") RepairVehicle();
            else if (cmd == "!invuln_tires") InvulnTires();
            else if (cmd == "!boost") BoostVehicle();
            else if (cmd == "!puncture") PunctureTire();
            else if (cmd == "!stall") StallEngine();
            else if (cmd == "!reduce_grip") ReduceGrip();
            // Other commands (!clear_pursuit, !escort_npc, !pursuit_vehicle, !detour_checkpoint, !explosion_safe)
            // are silently ignored due to unavailable SHVDN APIs.
        }

        // --- Mission lifecycle ---
        private void StartMission(Vehicle playerVehicle)
        {
            CleanupMission();

            missionVehicle = playerVehicle;
            if (missionVehicle == null || !missionVehicle.Exists())
            {
                GTA.UI.Notification.Show("~r~Invalid vehicle.");
                return;
            }

            // Reset vehicle to base state
            missionVehicle.CanTiresBurst = true;
            missionVehicle.EnginePowerMultiplier = 1.0f;
            missionVehicle.EngineTorqueMultiplier = 1.0f;
            ((Entity)missionVehicle).Health = ((Entity)missionVehicle).MaxHealth;

            missionStartTime = DateTime.Now;
            missionActive = true;
            missionFailed = false;
            missionSucceeded = false;
            tiresInvulnerable = false;
            engineBoosted = false;
            tractionReduced = false;
            engineStalled = false;
            cooldowns.Clear();

            GTA.UI.Notification.Show("~g~Mission started! Survive for 10 minutes inside this vehicle.");
        }

        private void SucceedMission()
        {
            missionSucceeded = true;
            missionActive = false;
            GTA.UI.Notification.Show("~g~Mission SUCCESS! You survived.");
            CleanupMission();
        }

        private void FailMission(string reason)
        {
            missionFailed = true;
            missionActive = false;
            GTA.UI.Notification.Show("~r~Mission FAILED: " + reason);
            CleanupMission();
        }

        private void CleanupMission()
        {
            if (missionVehicle != null && missionVehicle.Exists())
            {
                // Restore default multipliers
                missionVehicle.EnginePowerMultiplier = 1.0f;
                missionVehicle.EngineTorqueMultiplier = 1.0f;
                missionVehicle.CanTiresBurst = true;
            }
            missionVehicle = null;

            tiresInvulnerable = false;
            engineBoosted = false;
            tractionReduced = false;
            engineStalled = false;
            cooldowns.Clear();
            missionActive = false;
            missionFailed = false;
            missionSucceeded = false;
        }

        // --- Cooldown helper ---
        private bool TryCooldown(string key, int seconds)
        {
            if (cooldowns.TryGetValue(key, out DateTime end) && DateTime.Now < end)
                return false;
            cooldowns[key] = DateTime.Now.AddSeconds(seconds);
            return true;
        }

        // --- Chat command effects (all on main thread) ---

        private void RepairVehicle()
        {
            if (!TryCooldown("repair", 10)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            Entity ent = (Entity)missionVehicle;
            int add = (int)(ent.MaxHealth * 0.25f);
            int newHealth = Math.Min(ent.Health + add, ent.MaxHealth);
            ent.Health = newHealth;
            GTA.UI.Notification.Show("~b~+25% health");
        }

        private void InvulnTires()
        {
            if (!TryCooldown("invuln_tires", 15)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            tiresInvulnerable = true;
            tireInvulnEnd = DateTime.Now.AddSeconds(30);
            missionVehicle.CanTiresBurst = false;
            GTA.UI.Notification.Show("~b~Bulletproof tires for 30s");
        }

        private void BoostVehicle()
        {
            if (!TryCooldown("boost", 20)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            engineBoosted = true;
            engineBoostEnd = DateTime.Now.AddSeconds(5);
            // Power will be updated in OnTick (priority logic)
            GTA.UI.Notification.Show("~b~Speed boost for 5s");
        }

        private void PunctureTire()
        {
            if (!TryCooldown("puncture", 5)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            Entity ent = (Entity)missionVehicle;
            ent.Health = Math.Max(ent.Health - 25, 1);
            GTA.UI.Notification.Show("~r~Tire punctured! Vehicle damaged.");
        }

        private void StallEngine()
        {
            if (!TryCooldown("stall", 10)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            engineStalled = true;
            engineStallEnd = DateTime.Now.AddSeconds(4);
            // Power will be set to 0 by OnTick priority
            GTA.UI.Notification.Show("~r~Engine stalled!");
        }

        private void ReduceGrip()
        {
            if (!TryCooldown("reduce_grip", 10)) return;
            if (missionVehicle == null || !missionVehicle.Exists()) return;
            tractionReduced = true;
            tractionReducedEnd = DateTime.Now.AddSeconds(8);
            missionVehicle.EngineTorqueMultiplier = 0.3f;
            GTA.UI.Notification.Show("~r~Reduced traction for 8s");
        }

        // --- UI helpers ---
        private void DisplayTimer(TimeSpan remaining)
        {
            string time = $"{remaining.Minutes:D2}:{remaining.Seconds:D2}";
            GTA.UI.Screen.ShowSubtitle($"~w~Time left: ~y~{time}");
        }
    }
}
